# -*- coding: utf-8 -*-
import zlib
import base64
from Crypto.Cipher import AES
from Crypto.Protocol.KDF import scrypt

PASSWORD = "#[123qweasdzxc#cxzdsaewq321]#"

encrypted_data_b64 = """"""

def decrypt_aes_gcm(encrypted_package, password):

    data = base64.b64decode(encrypted_data_b64)

    salt = data[:16]
    nonce = data[16:32]
    tag = data[32:48]
    ciphertext = data[48:]

    key = scrypt(password, salt, 32, N=2**14, r=8, p=1)

    cipher = AES.new(key, AES.MODE_GCM, nonce=nonce)

    try:
        decrypted_data = cipher.decrypt_and_verify(ciphertext, tag)
        return decrypted_data
    except ValueError:
        raise Exception("Kesalahan integritas data atau password salah!")

if __name__ == "__main__":
    compressed_code = decrypt_aes_gcm(encrypted_data_b64, PASSWORD)

    original_code_bytes = zlib.decompress(compressed_code)

    exec(original_code_bytes.decode('utf-8'))
